    99|/** Map a thrown gateway error into a coarse class. */
   100|export function classifyProviderFailure(error: unknown): IVXProviderFailureClass {
   101|  if (!error) return 'unknown';
   102|  const name = error instanceof Error ? error.name : '';
   103|  const message = error instanceof Error ? error.message.toLowerCase() : String(error).toLowerCase();
   104|  const statusMatch = message.match(/status=(\d{3})/);
   105|  const status = statusMatch ? Number.parseInt(statusMatch[1], 10) : null;
   106|
   107|  if (name === 'IVXAIGatewayTimeoutError' || message.includes('timed out') || message.includes('etimedout')) {
   108|    return 'timeout';
   109|  }
   110|  if (status === 401 || status === 403 || message.includes('unauthor') || message.includes('forbidden')) {
   111|    return 'auth';
   112|  }
   113|  if (status === 429 || message.includes('rate-limit') || message.includes('rate limit')) {
   114|    return 'rate_limit';
   115|  }
   116|  if (message.includes('insufficient_quota') || message.includes('quota')) {
   117|    return 'quota';
   118|  }
   119|  if (status && status >= 500) {
   120|    return 'server_error';
   121|  }
   122|  if (status === 400 || status === 422) {
   123|    return 'bad_request';
   124|  }
   125|  if (message.includes('econnreset') || message.includes('fetch failed') || message.includes('network')) {
   126|    return 'network';
   127|  }
   128|  return 'unknown';
   129|}
