  // and is handled by callRorkToolkitNative, which uses a direct fetch with the
  // toolkit bearer.
  const rorkToolkitKey = getRorkToolkitKey();
  if (rorkToolkitKey) {
    candidates.push(RORK_TOOLKIT_NATIVE_URL);
  }

